sys_script_include.script:
var ApiTokenService = Class.create();
ApiTokenService.prototype = {
    initialize: function() {
        this.logger = new Logger('ApiTokenService');
    },

    validate: function(token) {
        try {
            var r = new HttpRequestUtils();
            var headers = {};
            headers[Constants.DC_ONE_AUTH_HEADER] = token;
            var response = r.get(Constants.URL.validateAPITokenUrl, headers);

            var result =
                response ===
                "Hello from DigiCert ONE - Trust Lifecycle Manager REST API!";

            if (result) {
                var gr = new GlideRecord(Constants.APPLICATION_SECURITY_PROPERTY.table);
                gr.addQuery(
                    "property",
                    Constants.APPLICATION_SECURITY_PROPERTY.digicertOneApiKey
                );
                gr.query();

                if (gr.next()) {
                    gr.value = token;
                    gr.update();
                } else {
                    gr.property = Constants.APPLICATION_SECURITY_PROPERTY.digicertOneApiKey;
                    gr.value = token;
                    gr.update();
                }
            }

            return result;
        } catch (e) {
            this.logger.error('validate(token): Error - {0}', e.message);
            throw e;
        }
    },

    type: 'ApiTokenService'
};
